from flask import Flask, session, request

app = Flask(__name__)
app.config['SECRET_KEY'] = 'yoursecretkeygoeshere'

@app.route('/')
def index():
    if not 'username' in session:
        return '<h1>Welcome!</h1><p>Please log in.</p>'
    else:
        return f'<h1>Welcome back, {session["username"]}!</h1><p>Your last visited page was <a href="{request.referrer}">{request.referrer}</a>.</p><form action="/logout" method="post"><input type="submit" value="Log out"></form>'

@app.route('/login', methods=['POST'])
def login():
    session['username'] = request.form['username']
    return 'You are now logged in.'

@app.route('/logout')
def logout():
    session.pop('username', None)
    return 'You have been logged out.'